+                }
+                let actual_as = (Gf256(a) * Gf256(b)).0;
+                if actual_as != expected {
+                    fail_mismatch(
+                        "mul_tables_match_logexp",
+                        a,
+                        b,
+                        expected,
+                        actual_as,
