+    let mut receiver = RaptorQReceiverBuilder::new()
+        .config(config)
+        .source(VecStream::new(symbols))
+        .build()
+        .expect("receiver build");
+    let got = receiver
+        .receive_object(&cx, &params)
+        .expect("receive_object")
+        .data;
+
+    assert_eq!(got, data);
+}

