+        let mut hasher = blake3::Hasher::new();
+        hasher.update(ObjectId::DOMAIN_SEPARATOR);
+        hasher.update(&canonical);
+        let digest = hasher.finalize();
+        let mut expected = [0u8; 16];
+        expected.copy_from_slice(&digest.as_bytes()[..16]);
